using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    void ApplyMigrations(AppDbContext db)
    {
        // Breaking change (EF Core 9): Migrate() now manages its own
        // transactions internally and throws if called inside a user transaction.
        // The execution strategy wrapper is still valid for transient-fault retry.
        var strategy = db.Database.CreateExecutionStrategy();
        strategy.Execute(() =>
        {
            db.Database.Migrate();
        });
    }
}

