using Microsoft.EntityFrameworkCore;

// Demonstrates the two Cosmos DB breaking changes in EF Core 9:
//   1. Default discriminator JSON property changed from "Discriminator" to "$type"
//   2. Synchronous I/O on the Cosmos provider now throws

class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
        => options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "CatalogDb");

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change: EF Core 9 writes "$type" into the JSON document
        // instead of "Discriminator". Existing documents still use the old name,
        // so we must pin it back to keep reads working.
        modelBuilder.Entity<Product>()
            .ToContainer("Products")
            .HasPartitionKey(p => p.Category)
            .HasDiscriminator<string>("Discriminator");

        modelBuilder.Entity<Product>()
            .Property("Discriminator")
            .ToJsonProperty("Discriminator");
    }
}

class Product
{
    public string Id { get; set; } = null!;
    public string Name { get; set; } = null!;
    public string Category { get; set; } = null!;
}

// Breaking change: Synchronous Cosmos queries (ToList, First, SaveChanges, …)
// now throw InvalidOperationException. All calls must be async.
class ProductService
{
    private readonly CosmosDbContext _db;
    public ProductService(CosmosDbContext db) => _db = db;

    // ── BEFORE (EF Core 8 — sync, now throws in EF Core 9) ──
    // public List<Product> GetByCategory(string cat)
    //     => _db.Products.Where(p => p.Category == cat).ToList();
    //
    // public void Create(Product p) { _db.Products.Add(p); _db.SaveChanges(); }

    // ── AFTER (EF Core 9 — async) ──
    public async Task<List<Product>> GetByCategoryAsync(string cat)
        => await _db.Products.Where(p => p.Category == cat).ToListAsync();

    public async Task CreateAsync(Product p)
    {
        _db.Products.Add(p);
        await _db.SaveChangesAsync();
    }
}

